@strawberry.type
class Query:
    @strawberry.field
    def product(self, info, id: int) -> ProductType | None:
        db = SessionLocal()
        try:
            return db.query(Product).filter(Product.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def products(self, info, limit: int = 100) -> list[ProductType]:
        db = SessionLocal()
        try:
            return db.query(Product).limit(limit).all()
        finally:
            db.close()
    
    @strawberry.field
    def category(self, info, id: int) -> CategoryType | None:
        db = SessionLocal()
        try:
            return db.query(Category).filter(Category.id == id).first()
        finally:
            db.close()
    
    @strawberry.field
    def seller(self, info, id: int) -> SellerType | None:
        db = SessionLocal()
